  ('fire-eq-eng-moex-00325', 'fire-eq-eng', 'fire-eq-eng-moex-112-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依複合用途建築物判斷基準之規定，一棟建築物中供住宅使用之樓地板合計面積為 2500 平 方公尺，另供乙類場所之補習班（300平方公尺）、訓練班（400平方公尺）、K書中心（500 平方公尺）、兒童課後照顧服務中心（600平方公尺）及金融機構（700平方公尺），試問此一 棟建築物應視為下列何種用途建築物？', '["複合用途建築物", "住宅用途建築物", "金融機構用途建築物", "各自用途之建築物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "dd6f3dcd0b73", "answer_pdf_sha1": "993bbcb4aefe", "source_family": "moex-gov-tw", "moex": {"exam_code": "112060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "112", "exam_name": "112年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00326', 'fire-eq-eng', 'fire-eq-eng-moex-112-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防幫浦加壓送水裝置等及配管摩擦損失計算基準所述之技術用語定義，下列敘述何者 正確？', '["加壓送水裝置等：水源之水位低於幫浦位置時，常時充水於幫浦及配管之裝置", "呼水裝置：消防栓開關開啟，配管內水壓降低，或撒水頭動作，自動啟動加壓送水裝置之 裝置", "幫浦性能試驗裝置：確認加壓送水裝置之全揚程及出水量之試驗裝置", "啟動用水壓開關裝置：由幫浦、電動機之加壓送水裝置及控制盤、呼水裝置、防止水溫上 升用排放裝置、幫浦性能試驗裝置、啟動用水壓開關裝置、底閥等附屬裝置或附屬機器所 構成"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "dd6f3dcd0b73", "answer_pdf_sha1": "993bbcb4aefe", "source_family": "moex-gov-tw", "moex": {"exam_code": "112060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "112", "exam_name": "112年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00327', 'fire-eq-eng', 'fire-eq-eng-moex-112-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依複合用途建築物判斷基準之規定，有關建築物主用途及從屬用途關係對照表所述，主用途 部分樓地板面積合計應超過該建築物總樓地板面積百分之A以上，且從屬用途部分之樓地板 面積合計未超過B平方公尺。下列A與B何者正確？', '["A=85，B=400", "A=95，B=100", "A=80，B=500", "A=90，B=300"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "dd6f3dcd0b73", "answer_pdf_sha1": "993bbcb4aefe", "source_family": "moex-gov-tw", "moex": {"exam_code": "112060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "112", "exam_name": "112年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00328', 'fire-eq-eng', 'fire-eq-eng-moex-112-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依避難器具支固器具及固定部之結構、強度計算及施工方法之規定，有關裝置避難器具固定 部之承載荷重（kgf），下列敘述何者錯誤？', '["緩降機之承載荷重為最大使用人數乘以330", "袋長長度小於10公尺之直降式救助袋承載荷重為660", "袋長長度小於15公尺之斜降式救助袋承載荷重上端為375，下端為285", "避難橋之承載荷重為每1平方公尺330"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "dd6f3dcd0b73", "answer_pdf_sha1": "993bbcb4aefe", "source_family": "moex-gov-tw", "moex": {"exam_code": "112060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "112", "exam_name": "112年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00329', 'fire-eq-eng', 'fire-eq-eng-moex-112-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防安全設備測試報告書測試方法及判定要領，有關一一九火災通報裝置性能試驗之規定， 下列敘述何者錯誤？', '["每一區段之蓄積語音應在20秒內", "蓄積語音應在發出撥號信號並偵測應答後自動送出", "可正確偵測回撥信號，確認信號時可以音效表示，通報裝置側的電話機回撥時，其與試驗 機之消防機關側電話機間應可相互通話", "操作手動啟動裝置或連動啟動（限與火警自動警報設備連動者），消防機關側保持不應答 時，從通報裝置應繼續送出蓄積語音"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "dd6f3dcd0b73", "answer_pdf_sha1": "993bbcb4aefe", "source_family": "moex-gov-tw", "moex": {"exam_code": "112060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "112", "exam_name": "112年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00330', 'fire-eq-eng', 'fire-eq-eng-moex-112-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依滅火器性能檢查及藥劑更換充填作業專業廠商認可及管理要點，有關申請專業廠商認可者， 應符合資格之規定，下列何者錯誤？', '["取得公司或商業登記", "有必要之設備及器具", "有固定之作業場所", "置有專任符合消防法規定之消防專技人員（如消防設備師、消防設備士或暫行從事消防安 全設備裝置檢修人員）至少2人，且不得同時任職於其他工廠或公司（商業）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "dd6f3dcd0b73", "answer_pdf_sha1": "993bbcb4aefe", "source_family": "moex-gov-tw", "moex": {"exam_code": "112060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "112", "exam_name": "112年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00331', 'fire-eq-eng', 'fire-eq-eng-moex-112-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依潔淨區消防安全設備設置要點之規定，潔淨室、上回風層、下回風層及回風豎井頂部應設 置密閉濕式自動撒水設備，並應符合之規定，下列敘述何者正確？', '["撒水密度每平方公尺每分鐘8公升以上，其計算方式由中央消防主管機關另定之", "水源容量應在最遠之20個撒水頭連續放射30分鐘之水量以上。但撒水頭數未達30個者， 依實際撒水頭數計算水量", "氣淋室得免設撒水頭", "撒水頭應為一般反應型（第二種感度）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "dd6f3dcd0b73", "answer_pdf_sha1": "993bbcb4aefe", "source_family": "moex-gov-tw", "moex": {"exam_code": "112060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "112", "exam_name": "112年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00332', 'fire-eq-eng', 'fire-eq-eng-moex-112-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依原有合法建築物防火避難設施及消防設備改善辦法之規定，有關醫院、戲院、電影院、歌 廳、演藝場、商場（包括營業面積在1500平方公尺以上之加工服務部）、舞廳、遊藝場、集 會堂及市場等建築物，直通樓梯及平臺淨寬不得小於多少？', '["75公分", "1.2公尺", "1.3公尺", "1.4公尺"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "dd6f3dcd0b73", "answer_pdf_sha1": "993bbcb4aefe", "source_family": "moex-gov-tw", "moex": {"exam_code": "112060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "112", "exam_name": "112年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
